import{_ as t,o,c as r,ag as a}from"./chunks/framework.DXGyWiRo.js";const f=JSON.parse('{"title":"QGroundControl Software","description":"","frontmatter":{},"headers":[],"relativePath":"robotics/qgroundcontrol-software.md","filePath":"robotics/qgroundcontrol-software.md"}'),i={name:"robotics/qgroundcontrol-software.md"};function s(n,e,l,u,d,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="qgroundcontrol-software" tabindex="-1">QGroundControl Software <a class="header-anchor" href="#qgroundcontrol-software" aria-label="Permalink to &quot;QGroundControl Software&quot;">​</a></h1><p>QGroundControl (QGC) is the Graphical User Interface (GUI) for ArduSub, which provides setup and control functionality. QGC runs on Windows, OS X, and Linux platforms.</p><p>Key Features:</p><ul><li>Full setup/configuration of ArduSub powered vehicles.</li><li>Video streaming with instrument display overlays.</li><li>Map display showing vehicle position, track, and waypoints for vehicles using an underwater positioning system.</li></ul><p>The QGC user interface is implemented using <a href="http://doc.qt.io/qt-5/qtqml-index.html" target="_blank" rel="noreferrer">Qt QML</a>. QML provides for hardware acceleration which is a key feature on lower powered devices such as tablets or phones. QML also provides features which allows creation of a single user interface which can adapt itself to differing screen sizes and resolution.</p><h2 id="versioning" tabindex="-1">Versioning <a href="#versioning" id="versioning"></a> <a class="header-anchor" href="#versioning" aria-label="Permalink to &quot;Versioning &lt;a href=&quot;#versioning&quot; id=&quot;versioning&quot;&gt;&lt;/a&gt;&quot;">​</a></h2><p>There are two versions of QGroundControl software:</p><ul><li>Stable (4.0.X): The recommended build for most users.</li><li>Daily (Development HEAD | Git Revision | Date | Time): Development build, updated frequently. These builds are for development purposes only and not recommended for regular use.</li></ul><h3 id="what-version-is-installed" tabindex="-1">What Version is Installed? <a href="#what-version-is-installed" id="what-version-is-installed"></a> <a class="header-anchor" href="#what-version-is-installed" aria-label="Permalink to &quot;What Version is Installed? &lt;a href=&quot;#what-version-is-installed&quot; id=&quot;what-version-is-installed&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>To find out what software version is installed on your topside computer, navigate to the <em>Application Settings</em> and scroll to the bottom of the <em>General</em> tab.</p><h3 id="release-history" tabindex="-1">Release History <a href="#release-history" id="release-history"></a> <a class="header-anchor" href="#release-history" aria-label="Permalink to &quot;Release History &lt;a href=&quot;#release-history&quot; id=&quot;release-history&quot;&gt;&lt;/a&gt;&quot;">​</a></h3><p>QGroundControl release history is available <a href="https://docs.qgroundcontrol.com/en/releases/release_notes.html" target="_blank" rel="noreferrer">here</a>.</p><h3 id="results-matching" tabindex="-1">results matching &quot;&quot; <a class="header-anchor" href="#results-matching" aria-label="Permalink to &quot;results matching &quot;&quot;&quot;">​</a></h3><ul><li></li></ul><h3 id="no-results-matching" tabindex="-1">No results matching &quot;&quot; <a class="header-anchor" href="#no-results-matching" aria-label="Permalink to &quot;No results matching &quot;&quot;&quot;">​</a></h3>',15)])])}const p=t(i,[["render",s]]);export{f as __pageData,p as default};
